class Solution {
public:
int firstDeletedIndex(std::vector<int>& nums, int target) {
    int n = nums.size();
    int prefix_xor = 0;
    for (int i = 0; i < n; ++i) {
        prefix_xor ^= nums[i];
    }
    int suffix_xor = 0;
    for (int i = n - 1; i >= 0; --i) {
        suffix_xor ^= nums[i];
    }
    int result = -1;
    for (int i = 0; i < n; ++i) {
        if ((prefix_xor ^ suffix_xor) == nums[i]) {
            result = i;
            break;
        }
    }
    return result;
}
};
